// Create default cell types grid (all fixed)
function makeDefaultCells(cols, rows) {
  const cells = [];
  for (let r = 0; r < rows; r++) {
    const row = [];
    for (let c = 0; c < cols; c++) row.push("fixed");
    cells.push(row);
  }
  return cells;
}

